INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-785d-a580-ef1526ec185d', 'CHM112: Acid-Base Titration & pH Measurement', '2025-11-01T17:29:16.208675+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:29:16.208675+00:00', 'Clarify the process of determining the equivalence point using both indicator and pH meter methods.', '019b3be4-36d5-7286-bc26-166caa8a95ec', true, false, false) ON CONFLICT (id) DO NOTHING;
