INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:29:16.208675+00:00', 'Explain how to calculate the concentration of an unknown acid from titration data.', '019b3be4-36d5-72f1-ab02-d44f7c8439d7', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:29:16.208675+00:00', 'CHM112: Acid-Base Titration & pH Measurement', 'In the quiet of an almost empty Herbert C. Brown Laboratory early in the morning, a student leans over their lab notebook, puzzling over the details of acid-base titration and pH measurement, and asks a series of questions about equivalence points and indicator choices with a deadline still a couple of days away.', '019b3be4-36ec-74c8-9a3a-f74512206235', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids, parameter_ids, parent_id) VALUES ('2025-11-01T17:29:16.208675+00:00', true, false, false, '019bb25e-e61d-7b63-a591-de2ef3b61f7a', 'CHM112: Acid-Base Titration & pH Measurement', 'Chemistry lab scenario focusing on acid-base titration and pH measurement techniques.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7345-ac6d-50d29df6deb3}', '{}', '019bb25e-e61d-7b63-a591-de2ef3b61f7a') ON CONFLICT (id) DO NOTHING;
